using System.Diagnostics;
using System.Runtime.CompilerServices;
using TextAnalysis;

const int WarmupIterations = 500;
const int BatchSize = 5000;
const int Rounds = 10;
int[] wordCounts = [100, 1000];

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Warmup: {WarmupIterations}, Batch: {BatchSize} ops x {Rounds} rounds");
Console.WriteLine(new string('-', 85));
Console.WriteLine($"{"Method",-25} {"WordCount",10} {"Mean (ns/op)",15} {"StdDev (ns/op)",15} {"Alloc (B/op)",15}");
Console.WriteLine(new string('-', 85));

foreach (int wordCount in wordCounts)
{
    var analyzer = CreateAnalyzer(wordCount);

    Benchmark("AverageWordLength", wordCount, () => { analyzer.AverageWordLength(); });
    Benchmark("WordLengthHistogram", wordCount, () => { analyzer.WordLengthHistogram(); });
    Benchmark("UniqueWordCount", wordCount, () => { analyzer.UniqueWordCount(); });
}

Console.WriteLine(new string('-', 85));

static TextAnalyzer CreateAnalyzer(int wordCount)
{
    var rng = new Random(42);
    var words = new string[wordCount];
    for (int i = 0; i < wordCount; i++)
    {
        int len = rng.Next(2, 12);
        var chars = new char[len];
        for (int j = 0; j < len; j++)
            chars[j] = (char)('a' + rng.Next(0, 26));
        words[i] = new string(chars);
    }
    return new TextAnalyzer(string.Join(' ', words));
}

static void Benchmark(string name, int wordCount, Action action)
{
    // Warmup
    for (int i = 0; i < WarmupIterations; i++)
        action();

    // Measure allocations
    GC.Collect();
    GC.WaitForPendingFinalizers();
    GC.Collect();
    long allocBefore = GC.GetTotalAllocatedBytes(precise: true);
    for (int i = 0; i < BatchSize; i++)
        action();
    long allocAfter = GC.GetTotalAllocatedBytes(precise: true);
    long allocPerOp = (allocAfter - allocBefore) / BatchSize;

    // Measure time in rounds of batches
    var sw = new Stopwatch();
    var roundMeans = new double[Rounds];

    for (int r = 0; r < Rounds; r++)
    {
        GC.Collect();
        GC.WaitForPendingFinalizers();
        GC.Collect();

        sw.Restart();
        for (int i = 0; i < BatchSize; i++)
            action();
        sw.Stop();

        roundMeans[r] = sw.Elapsed.TotalNanoseconds / BatchSize;
    }

    double mean = roundMeans.Average();
    double variance = roundMeans.Select(t => (t - mean) * (t - mean)).Average();
    double stddev = Math.Sqrt(variance);

    Console.WriteLine($"{name,-25} {wordCount,10} {mean,15:F2} {stddev,15:F2} {allocPerOp,15}");
}

